import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Escape special characters in user input
        String sanitizedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Output sanitized user input on the web page
        try (PrintWriter out = new PrintWriter("output.html")) {
            out.println("<html>");
            out.println("<head><title>XSS Fixed Code Demo</title></head>");
            out.println("<body>");
            out.println("<h1>User Input: " + sanitizedUserInput + "</h1>"); // Sanitized user input
            out.println("</body>");
            out.println("</html>");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
